class PriceCalculator {
  calculate(price: number, discountType: string): number {
    if (discountType === 'none') {
      return price;
    } else if (discountType === 'percentage') {
      return price * 0.9;
    } else if (discountType === 'flat') {
      return price - 10;
    } else if (discountType === 'bogo') {
      return price / 2;
    }
    throw new Error('Unknown discount type');
  }
}

class DataSorter {
  sort(data: number[], algorithm: 'bubble' | 'quick' | 'merge'): number[] {
    switch (algorithm) {
      case 'bubble': return this.bubbleSort(data);
      case 'quick':  return this.quickSort(data);
      case 'merge':  return this.mergeSort(data);
    }
  }

  private bubbleSort(data: number[]): number[] { return []; }
  private quickSort(data: number[]): number[] { return []; }
  private mergeSort(data: number[]): number[] { return []; }
}

