class ShippingCalculator {
  calculate(carrier: string, weight: number): number {
    if (carrier === 'fedex') return weight * 2.5;
    if (carrier === 'ups')   return weight * 2.8;
    throw new Error('Unknown carrier');
  }
}
// Version B
interface ShippingStrategy { calculate(weight: number): number; }
class ShippingCalculator {
  constructor(private s: ShippingStrategy) {}
  calculate(weight: number): number { return this.s.calculate(weight); }
}
